#!/usr/bin/env python3
"""
summarise_benchmarks.py

Reads all BenchmarkDotNet JSON result files from the matrix artifact directories
and produces a single consolidated Markdown table grouped by OS and .NET version.

Usage:
    python3 summarise_benchmarks.py \
        --artifacts-dir all-artifacts \
        --output docs/benchmark-results.md
"""

import argparse
import json
import re
from dataclasses import dataclass
from pathlib import Path
from typing import Optional


@dataclass
class BenchmarkResult:
    method:  str
    mean_ns: float
    ratio:   Optional[float]
    os:      str
    dotnet:  str


def parse_artifacts(artifacts_dir: Path) -> list[BenchmarkResult]:
    results: list[BenchmarkResult] = []

    for artifact_dir in sorted(artifacts_dir.iterdir()):
        if not artifact_dir.is_dir():
            continue

        # Directory name: benchmark-results-<os>-net<dotnet>
        # e.g. benchmark-results-ubuntu-latest-net10.0
        name = artifact_dir.name
        m = re.match(r'benchmark-results-(.+)-net(\d+\.\d+)$', name)
        if not m:
            continue

        os_name = m.group(1).replace('-latest', '').replace('-', ' ').title()
        dotnet  = m.group(2)

        # Walk recursively to find all *.json result files
        for json_file in artifact_dir.rglob('*.json'):
            try:
                data = json.loads(json_file.read_text(encoding='utf-8'))
            except (json.JSONDecodeError, OSError):
                continue

            for bench in data.get('Benchmarks', []):
                method   = bench.get('MethodTitle', bench.get('Method', 'Unknown'))
                mean_ns  = bench.get('Statistics', {}).get('Mean', 0.0)
                ratio    = bench.get('Ratio')   # may be None for baseline

                results.append(BenchmarkResult(
                    method=method,
                    mean_ns=mean_ns,
                    ratio=ratio,
                    os=os_name,
                    dotnet=dotnet,
                ))

    return results


def fmt_ns(ns: float) -> str:
    """Format nanoseconds with appropriate unit."""
    if ns >= 1_000_000:
        return f"{ns / 1_000_000:.2f} ms"
    if ns >= 1_000:
        return f"{ns / 1_000:.2f} µs"
    return f"{ns:.2f} ns"


def build_markdown(results: list[BenchmarkResult]) -> str:
    lines: list[str] = []

    lines.append("# CedarRecon — Modulo Resolver Benchmark Results")
    lines.append("")
    lines.append("> Auto-generated by CI. Do not edit manually.")
    lines.append("> Re-runs on every push to `main` that touches `Matching/Strategies/` or the benchmark project.")
    lines.append("")
    lines.append("## What this measures")
    lines.append("")
    lines.append("Three implementations of `sourceAmount % candidateAmount == 0` used by `PartialMatchStrategy`:")
    lines.append("- **Decimal** — direct `decimal %`, no assumptions, CLR software-emulated")
    lines.append("- **ScaledLong** — scale both to `long × 10_000`, use integer `%`")
    lines.append("- **UnsafeMantissa** — read raw mantissa via struct overlay, `UInt128 %`")
    lines.append("")
    lines.append("See [`docs/modulo-resolver.md`](modulo-resolver.md) for the full engineering rationale.")
    lines.append("")

    # Group by dotnet, then os
    dotnet_versions = sorted(set(r.dotnet for r in results), reverse=True)
    oses            = sorted(set(r.os     for r in results))
    methods         = ['Decimal', 'ScaledLong', 'UnsafeMantissa']

    lines.append("## Isolated call — `ModuloBenchmark`")
    lines.append("")
    lines.append("Single modulo call. Source = `99_999.9999`, Candidate = `9_999.9999` (÷10, clean divisor).")
    lines.append("")

    for dotnet in dotnet_versions:
        lines.append(f"### .NET {dotnet}")
        lines.append("")
        lines.append(f"| OS | {' | '.join(methods)} | Winner |")
        lines.append(f"|:-- |{'|'.join([' --:' for _ in methods])}| :-- |")

        for os_name in oses:
            row_results = {
                r.method: r
                for r in results
                if r.dotnet == dotnet and r.os == os_name
            }

            if not row_results:
                lines.append(f"| {os_name} | — | — | — | — |")
                continue

            cells    = []
            min_mean = min((r.mean_ns for r in row_results.values()), default=0)
            winner   = ''

            for method in methods:
                if method in row_results:
                    r     = row_results[method]
                    value = fmt_ns(r.mean_ns)
                    # Bold the fastest
                    if r.mean_ns == min_mean:
                        value  = f"**{value}**"
                        winner = method
                    cells.append(value)
                else:
                    cells.append('—')

            lines.append(f"| {os_name} | {' | '.join(cells)} | {winner} |")

        lines.append("")

    # Decision table
    lines.append("## Decision summary")
    lines.append("")
    lines.append("| Runtime | Recommended resolver | Reason |")
    lines.append("|:------- |:-------------------- |:------ |")
    lines.append("| .NET 10 | `Decimal` | JIT optimises `decimal %` well; ScaledLong pre-multiply dominates |")
    lines.append("| .NET 9  | `Decimal` | Same JIT improvements |")
    lines.append("| .NET 8  | Run benchmark first | ScaledLong may win; verify on target hardware |")
    lines.append("")
    lines.append("## How to change the resolver")
    lines.append("")
    lines.append("```json")
    lines.append("// appsettings.json")
    lines.append("{")
    lines.append('  "CedarRecon": {')
    lines.append('    "ModuloResolver": "Decimal"   // "Decimal" | "ScaledLong" | "UnsafeMantissa"')
    lines.append("  }")
    lines.append("}")
    lines.append("```")
    lines.append("")
    lines.append("See [`docs/modulo-resolver.md`](modulo-resolver.md) for DI wiring examples.")

    return '\n'.join(lines)


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--artifacts-dir', required=True, type=Path)
    parser.add_argument('--output',        required=True, type=Path)
    args = parser.parse_args()

    results  = parse_artifacts(args.artifacts_dir)
    markdown = build_markdown(results)

    args.output.parent.mkdir(parents=True, exist_ok=True)
    args.output.write_text(markdown, encoding='utf-8')

    print(f"Written {len(results)} benchmark results to {args.output}")


if __name__ == '__main__':
    main()